mapper.select:
SELECT A.homepage_id, A.excursions_idx, A.start_date, A.start_time, A.end_date, A.end_time,A.apply_start_date, A.apply_start_time, A.apply_end_date, A.apply_end_time, A.max_apply, A.add_date, A.date_type, (SELECT CODE_NAME FROM CMS_CODE B WHERE B.HOMEPAGE_ID = A.HOMEPAGE_ID AND B.CODE_ID = A.DATE_TYPE AND B.GROUP_ID = 'H0001') AS CODE_NAME, (SELECT COUNT(*) FROM CMS_CALENDAR_MANAGE B WHERE A.HOMEPAGE_ID = B.HOMEPAGE_ID AND A.HOMEPAGE_ID = #{homepage_id} AND B.DATE_TYPE = '1' AND B.DELETE_YN = 'N' AND A.START_DATE <= B.END_DATE AND A.END_DATE >= B.START_DATE) AS CLOSED_DAY, (SELECT COUNT(*) FROM CMS_EXCURSIONS_APPLY C WHERE A.HOMEPAGE_ID = C.HOMEPAGE_ID AND A.HOMEPAGE_ID = #{homepage_id} AND A.excursions_idx = C.excursions_idx) AS APPLY_COUNT, case when A.apply_start_date is null then apply_yn when SYSDATE between to_date(A.apply_start_date || ' ' || A.apply_start_time, 'yyyy-mm-dd hh24:mi') and to_date(A.apply_end_date || ' ' || A.apply_end_time, 'yyyy-mm-dd hh24:mi') then 'Y' else 'N' end as apply_yn FROM CMS_EXCURSIONS A WHERE 1=1 AND A.HOMEPAGE_ID = #{homepage_id}
AND A.DATE_TYPE = #{date_type}
AND (substr(A.start_date,1,7) = #{plan_date} OR substr(A.end_date,1,7) = #{plan_date})
ORDER BY START_DATE, START_TIME

mapper.insert:
	INSERT INTO CMS_EXCURSIONS (

   )VALUES (
   		#{homepage_id}, (SELECT NVL(MAX(excursions_idx),0)+1 FROM CMS_EXCURSIONS), #{apply_yn}, #{start_date}, #{start_time},
   		#{end_date}, #{end_time}, #{apply_start_date}, #{apply_start_time}, #{apply_end_date}, #{apply_end_time}, #{max_apply}, SYSDATE, #{date_type}
	)
